#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define NX 4096
#define NY 4096
#define STEPS 1000

int main() {
    float *A = (float*)malloc(NX * NY * sizeof(float));
    float *B = (float*)malloc(NX * NY * sizeof(float));

    // Initialize arrays
    #pragma omp parallel for collapse(2)
    for (int j = 0; j < NY; j++) {
        for (int i = 0; i < NX; i++) {
            A[j * NX + i] = 0.0f;
            B[j * NX + i] = 0.0f;
        }
    }

    // Set boundary conditions
    #pragma omp parallel for
    for (int i = 0; i < NX; i++) {
        A[i] = 100.0f;               // top row
        A[(NY - 1) * NX + i] = 100.0f; // bottom row
    }
    #pragma omp parallel for
    for (int j = 0; j < NY; j++) {
        A[j * NX] = 100.0f;         // left column
        A[j * NX + NX - 1] = 100.0f; // right column
    }

    // Time stepping
    for (int t = 0; t < STEPS; t++) {
        #pragma omp parallel for collapse(2)
        for (int j = 1; j < NY - 1; j++) {
            for (int i = 1; i < NX - 1; i++) {
                B[j * NX + i] = 0.25f * (A[j * NX + (i + 1)] + A[j * NX + (i - 1)] +
                                         A[(j + 1) * NX + i] + A[(j - 1) * NX + i]);
            }
        }
        // Swap pointers
        float *tmp = A;
        A = B;
        B = tmp;
    }

    // Print center value as a simple output check
    printf("Center value: %f\n", A[(NY / 2) * NX + (NX / 2)]);

    free(A);
    free(B);

    return 0;
}
